@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            <div class="infinite-scroll-spinner"></div>
        </div>
    }
</div>

@code {
    /// <summary>The collection of items to render.</summary>
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    /// <summary>Template used to render each item.</summary>
    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    /// <summary>Whether more items are available to load.</summary>
    [Parameter]
    public bool HasMore { get; set; }

    /// <summary>Callback invoked when the sentinel element becomes visible.</summary>
    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;
    private bool _observerAttached;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-df835f236ad14d6dbb73e29a3167186e/infiniteScroll.js");
            _dotNetRef = DotNetObjectReference.Create(this);
        }

        if (HasMore && _module is not null && !_observerAttached)
        {
            _observerAttached = true;
            await _module.InvokeVoidAsync("observe", _sentinelRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;
        await OnLoadMore.InvokeAsync();
        _isLoading = false;

        if (!HasMore)
        {
            await DisconnectObserverAsync();
        }

        StateHasChanged();
    }

    private async Task DisconnectObserverAsync()
    {
        if (_module is not null && _observerAttached)
        {
            _observerAttached = false;
            await _module.InvokeVoidAsync("disconnect");
        }
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            await DisconnectObserverAsync();
        }
        catch (JSDisconnectedException) { }

        _dotNetRef?.Dispose();

        if (_module is not null)
        {
            try { await _module.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }
    }
}

let observer = null;

export function observe(sentinel, dotNetRef) {
    disconnect();

    observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync("OnSentinelVisible");
            }
        }
    }, { rootMargin: "0px 0px 200px 0px" });

    observer.observe(sentinel);
}

export function disconnect() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid #e0e0e0;
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: spin 0.8s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

